    uint32_t totalLength = static_cast<uint32_t>(x_shape->GetOriginShape().GetShapeSize());
    uint32_t N = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));
    uint32_t C = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    uint32_t H = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(2));
    uint32_t W = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(3));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const int64_t *groupsPtr = attrs->GetAttrPointer<int64_t>(0);
    uint32_t groups = static_cast<uint32_t>(*groupsPtr);

    uint32_t maxTile = UB_BUDGET_BYTES / sizeof(float);
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    uint32_t tileLen = maxTile;
    if (totalLength < tileLen) {
        tileLen = AlignDown(totalLength, ALIGN_ELEMS);
        if (tileLen == 0) tileLen = totalLength;
    }

    uint32_t numTiles = (tileLen == 0) ? 1u : CeilDiv(totalLength, tileLen);
    uint32_t blockDim = numTiles;
    if (blockDim < 8u) blockDim = 8u;
    if (blockDim > 24u) blockDim = 24u;

